function TenantDirectory({ tenants, properties }) {
  const { div, h1, span, table, thead, tbody, tr, th, td } = tags;
  const [search, setSearch] = createSignal('');
  const [statusFilter, setStatusFilter] = createSignal('all');
  const [sortBy, setSortBy] = createSignal('name');

  const filtered = () => tenants.filter(t => {
    if (statusFilter() !== 'all' && t.paymentStatus !== statusFilter()) return false;
    if (search() && !t.name.toLowerCase().includes(search().toLowerCase()) && !t.email.toLowerCase().includes(search().toLowerCase())) return false;
    return true;
  }).sort((a, b) => a[sortBy()].localeCompare(b[sortBy()]));

  const active = tenants.filter(t => t.paymentStatus === 'current').length;
  const pastDue = tenants.filter(t => t.paymentStatus === 'overdue').length;
  const totalRent = tenants.reduce((sum, t) => sum + t.rent, 0);

  return div({ class: css('_flex _col _gap6') },
    div({ class: css('_flex _jcsb _aic') },
      h1({ class: css('_heading3') }, 'Tenants'),
      Button({ variant: 'primary' }, icon('user-plus'), 'Add Tenant')
    ),
    div({ class: css('_grid _cols4 _gap4') },
      div({ class: css('estate-card-metric _p4') },
        span({ class: css('_heading2 _block') }, tenants.length),
        span({ class: css('_textsm _fgmuted') }, 'Total Tenants')
      ),
      div({ class: css('estate-card-metric _p4') },
        span({ class: css('_heading2 _block _fgsuccess') }, active),
        span({ class: css('_textsm _fgmuted') }, 'Current')
      ),
      div({ class: css('estate-card-metric _p4') },
        span({ class: css('_heading2 _block _fgdanger') }, pastDue),
        span({ class: css('_textsm _fgmuted') }, 'Past Due')
      ),
      div({ class: css('estate-card-metric _p4') },
        span({ class: css('_heading2 _block') }, `$${totalRent.toLocaleString()}`),
        span({ class: css('_textsm _fgmuted') }, 'Monthly Rent')
      )
    ),
    div({ class: css('_flex _gap4 _aic') },
      Input({ type: 'search', placeholder: 'Search tenants...', value: search(), oninput: e => setSearch(e.target.value), class: css('_w64') }),
      Select({ value: statusFilter(), onchange: e => setStatusFilter(e.target.value) },
        tags.option({ value: 'all' }, 'All Status'),
        tags.option({ value: 'current' }, 'Current'),
        tags.option({ value: 'pending' }, 'Pending'),
        tags.option({ value: 'overdue' }, 'Past Due')
      ),
      Button({ variant: 'outline', class: css('_ml[auto]') }, icon('download'), 'Export')
    ),
    div({ class: css('estate-table _overflow[auto]') },
      table({ class: css('_wfull') },
        thead({},
          tr({ class: css('_bgSurface') },
            th({ class: css('_p3 _textleft _font500 _cursor[pointer]'), onclick: () => setSortBy('name') }, 'Tenant'),
            th({ class: css('_p3 _textleft _font500') }, 'Property / Unit'),
            th({ class: css('_p3 _tr _font500') }, 'Rent'),
            th({ class: css('_p3 _textleft _font500') }, 'Lease End'),
            th({ class: css('_p3 _tc _font500') }, 'Status'),
            th({ class: css('_p3') })
          )
        ),
        tbody({},
          ...filtered().map((t, i) =>
            tr({ class: css(i % 2 === 0 ? '' : '_bgSurfaceRaised') },
              td({ class: css('_p3') },
                div({ class: css('_flex _aic _gap3') },
                  Avatar({ src: t.avatar, alt: t.name, size: 'sm', fallback: t.name.charAt(0) }),
                  div({},
                    span({ class: css('_font500 _block') }, t.name),
                    span({ class: css('_textsm _fgmuted') }, t.email)
                  )
                )
              ),
              td({ class: css('_p3 _textsm') }, `${t.propertyName} - Unit ${t.unitNumber}`),
              td({ class: css('_p3 _tr _font500') }, `$${t.rent.toLocaleString()}`),
              td({ class: css('_p3 _textsm') }, t.leaseEnd),
              td({ class: css('_p3 _tc') }, Badge({ variant: t.paymentStatus === 'current' ? 'success' : t.paymentStatus === 'pending' ? 'warning' : 'danger' }, t.paymentStatus)),
              td({ class: css('_p3') },
                div({ class: css('_flex _gap1') },
                  Button({ variant: 'ghost', size: 'sm' }, icon('message-circle', { size: '16' })),
                  link({ href: `/tenants/${t.id}` }, Button({ variant: 'ghost', size: 'sm' }, icon('chevron-right', { size: '16' })))
                )
              )
            )
          )
        )
      )
    )
  );
}

function TenantCards({ tenants }) {
  const { div } = tags;
  return div({ class: css('_grid _cols3 _gap4') },
    ...tenants.map(tenant => TenantCard({ tenant }))
  );
}

